using Microsoft.AspNetCore.Http;
using System;
using System.IO;
namespace YourNamespaceName // replace with your namespace name if necessary  
{    
    public class FileUploadService 
    {        
        private const string UploadsFolder = "uploads";      
            
        public async Task<string> SaveFile(IFormFile file)     
        {           
           var uploadsFolderPath =  Path.Combine("wwwroot", UploadsFolder);   // get the path to wwwroot/Uploads folder 
                                                      
           if (!Directory.Exists(uploadsFolderPath))    // check whether directory exists or not, create it in case doesn't exist    
               Directory.CreateDirectory(uploadsFolderPath) ;            
            var fileName = Guid.NewGuid().ToString() + Path.GetExtension(file.FileName);  // generate a new unique name for the uploaded files  
                                                                                         
           using (var stream = new FileStream(Path.Combine(uploadsFolderPath, fileName), FileMode.Create))    {    
               await file.CopyToAsync(stream) ;      }                                                      
            return Path.Combine(UploadsFolder ,fileName);  //return the path to uploaded files in wwwroot/Upload folder  
        }      
}